function maxStudents(seats) {
    const m = seats.length;
    const n = seats[0].length;
    let validRows = new Array(m);
    const max_valid = (1 << n) - 1;

    for (let i = 0; i < m; i++) {
        let state = 0;
        for (let j = 0; j < n; j++) {
            state |= (seats[i][j] === '.') << j;
        }
        validRows[i] = state;
    }

    const memo = Array.from({ length: m }, () => Array(1 << n).fill(-1));
    return dfs(0, 0, validRows, m, n, max_valid, memo);
}

function dfs(rowIndex, prevState, validRows, m, n, max_valid, memo) {
    if (rowIndex === m) {
        return 0;
    }

    if (memo[rowIndex][prevState] !== -1) {
        return memo[rowIndex][prevState];
    }

    let maxStudents = 0;
    for (let curState = 0; curState <= max_valid; curState++) {
        if ((curState & validRows[rowIndex]) !== curState) continue;
        if (curState & (curState << 1)) continue;
        if (curState & (prevState << 1) || prevState & (curState << 1)) continue;

        const curStateCount = curState.toString(2).split("").reduce((sum, bit) => sum + (bit === '1' ? 1 : 0), 0);
        maxStudents = Math.max(maxStudents, dfs(rowIndex + 1, curState, validRows, m, n, max_valid, memo) + curStateCount);
    }

    memo[rowIndex][prevState] = maxStudents;
    return maxStudents;
}
```

    1. Convert each row into binary representation where '1' denotes a good seat and '0' denotes a broken seat.
2. Use a depth-first search with memorization to explore all valid states of students sitting in the classroom.
3. For each seat arrangement in a row, apply three conditions:
    a. Ensure students only sit on good seats.
    b. Students don't sit next to each other (left and right).
    c. Students don't sit on upper-left and upper-right seats of students from the previous row.
4. Recursively call the dfs function for each row, until all rows have been processed.
5. Keep track of the maximum number of students that can sit without cheating using memo table.
6. Return the maximum number of students that can take the exam together without any cheating being possible.

